+/// If the switch condition is a call to llvm.ucmp or llvm.scmp, and the
+/// switch cases correspond to the possible return values (-1, 0, 1), replace
+/// the switch with an icmp and a branch.
+static bool simplifySwitchOnCmpIntrinsic(SwitchInst *SI,
+                                         IRBuilder<> &Builder) {
+  Value *Cond = SI->getCondition();
+  auto *Cmp = dyn_cast<CmpIntrinsic>(Cond);
+  if (!Cmp)
+    return false;
+
+  // ucmp/scmp returns -1, 0, or 1. There should be at most 2 explicit cases.
+  if (SI->getNumCases() == 0 || SI->getNumCases() > 2)
+    return false;
+
+  bool HasDefault =
+      !isa<UnreachableInst>(SI->getDefaultDest()->getFirstNonPHIOrDbg());
+  BasicBlock *DefaultDest = HasDefault ? SI->getDefaultDest() : nullptr;
+  BasicBlock *DestMinus1 = DefaultDest;
+  BasicBlock *Dest0 = DefaultDest;
+  BasicBlock *Dest1 = DefaultDest;
+
+  for (auto &Case : SI->cases()) {
+    ConstantInt *CaseVal = Case.getCaseValue();
+    BasicBlock *CaseDest = Case.getCaseSuccessor();
+    if (CaseVal->isMinusOne())
+      DestMinus1 = CaseDest;
+    else if (CaseVal->isZero())
+      Dest0 = CaseDest;
+    else if (CaseVal->isOne())
+      Dest1 = CaseDest;
+    else
+      return false; // Unexpected case value for ucmp/scmp result.
+  }
+
+  // We need exactly 2 distinct destinations among the 3 possible values.
+  SmallPtrSet<BasicBlock *, 2> Destinations;
+  if (DestMinus1)
+    Destinations.insert(DestMinus1);
+  if (Dest0)
+    Destinations.insert(Dest0);
+  if (Dest1)
+    Destinations.insert(Dest1);
+  if (Destinations.size() != 2)
+    return false;
+
+  // Determine which destination is taken for the "true" branch.
+  auto It = Destinations.begin();
+  BasicBlock *DestA = *It++;
+  BasicBlock *DestB = *It;
+
+  // Determine which return values map to DestA.
+  bool Minus1ToA = (DestMinus1 == DestA);
+  bool ZeroToA = (Dest0 == DestA);
+  bool OneToA = (Dest1 == DestA);
+
+  Value *LHS = Cmp->getLHS();
+  Value *RHS = Cmp->getRHS();
+  CmpInst::Predicate Pred;
+
+  // Map the subset of values going to DestA to an icmp predicate.
+  if (OneToA && !ZeroToA && !Minus1ToA)
+    // {1} -> DestA: a > b
+    Pred = Cmp->getGTPredicate();
+  else if (!OneToA && ZeroToA && !Minus1ToA)
+    // {0} -> DestA: a == b
+    Pred = CmpInst::ICMP_EQ;
+  else if (!OneToA && !ZeroToA && Minus1ToA)
+    // {-1} -> DestA: a < b
+    Pred = Cmp->getLTPredicate();
+  else if (OneToA && ZeroToA && !Minus1ToA)
+    // {0, 1} -> DestA: a >= b
+    Pred = CmpInst::getInversePredicate(Cmp->getLTPredicate());
+  else if (!OneToA && ZeroToA && Minus1ToA)
+    // {-1, 0} -> DestA: a <= b
+    Pred = CmpInst::getInversePredicate(Cmp->getGTPredicate());
+  else if (OneToA && !ZeroToA && Minus1ToA)
+    // {-1, 1} -> DestA: a != b
+    Pred = CmpInst::ICMP_NE;
+  else
+    return false;
+
+  // Create the icmp and branch.
+  Builder.SetInsertPoint(SI);
+  Value *CmpResult = Builder.CreateICmp(Pred, LHS, RHS, "cmp");
+  Builder.CreateCondBr(CmpResult, DestA, DestB);
+
+  // Update PHI nodes in successors: remove incoming edges from the switch's
+  // parent for edges that are no longer present.
+  BasicBlock *BB = SI->getParent();
+  for (unsigned I = 0, E = SI->getNumSuccessors(); I != E; ++I) {
+    BasicBlock *Succ = SI->getSuccessor(I);
+    if (Succ != DestA && Succ != DestB) {
+      Succ->removePredecessor(BB);
+      // Also remove incoming values from PHI nodes in Succ that came from BB.
+      for (auto &Phi : Succ->phis())
+        Phi.removeIncomingValue(BB);
+    }
+  }
+
+  // The switch may have had multiple cases going to the same destination,
+  // The switch may have had multiple cases going to the same destination,
+  // resulting in duplicate entries in PHI nodes. After replacing the switch
+  // with a single conditional branch, we need to ensure each PHI node has
+  // at most one incoming value from BB.
+  for (BasicBlock *Succ : {DestA, DestB}) {
+    if (!Succ)
+      continue;
+    for (auto &Phi : Succ->phis()) {
+      // Check if there are multiple incoming values from BB.
+      int FirstIdx = Phi.getBasicBlockIndex(BB);
+      if (FirstIdx >= 0) {
+        // Remove any subsequent entries from BB (iterate backwards to
+        // preserve indices while removing).
+        for (int i = Phi.getNumIncomingValues() - 1; i > FirstIdx; --i) {
+          if (Phi.getIncomingBlock(i) == BB)
+            Phi.removeIncomingValue(i, /*DeletePHIIfEmpty=*/false);
+        }
+      }
+    }
+  }
+      }
+    }
+  }
+
+  // Erase the switch and the now-dead cmp intrinsic.
+  SI->eraseFromParent();
+  if (Cmp->use_empty())
+    Cmp->eraseFromParent();
+  return true;
+}
+
 /// Turn a switch into an integer range comparison and branch.
 /// Switches with more than 2 destinations are ignored.
 /// Switches with 1 destination are also ignored.
@@ -7153,6 +7285,10 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
         return requestResimplify();
   }

+  // Try to simplify switches on ucmp/scmp intrinsics.
+  if (simplifySwitchOnCmpIntrinsic(SI, Builder))
+    return requestResimplify();
+
   // Try to transform the switch into an icmp and a branch.
   // The conversion from switch to comparison may lose information on
   // impossible switch values, so disable it early in the pipeline.

